      "content": "// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');

const commentsStore = [];

module.exports = {
  getCommentsByTaskId(taskId) {
    return commentsStore.filter(comment => comment.taskId === taskId);
  },
  addComment(taskId, message) {
    const comment = { id: randomUUID(), taskId, message };
    commentsStore.push(comment);
    return comment;
  }
};
